vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


ret.r = GetBlur3(vUv).r*0.4;
//ret.r = GetPixel(vUv+vec2(0,0.0)).r*0.;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv += uTexSize.zw/2; uv0 = vUv;
float k1 = 10/q9;
dz.x = 2.0*GetBlur1(vUv+hor*k1).g-2.0*GetBlur1(vUv-hor*k1).g;
dz.y = 2.0*GetBlur1(vUv+ver*k1).g-2.0*GetBlur1(vUv-ver*k1).g;
dz *= GetBlur1(vUv).g > 0.08;
vUv += dz*0.08;

screen = vec3 ((vUv-0.5)*uAspect.xy+dz*.1,0.9);
rs0 = project()/12 ;
rs = rs0;
uv2 = vec2 (0.3*length(rs.xy), atan(rs.x,rs.y)/M_PI/4)/2;
uv3 = vec2 (1.3+.03/length(rs.xy), atan(rs.x,rs.y)/M_PI/2);
gnd = (texture(sampler_pw_noise_lq,uv2).r+1)/2;
gnd *= sat(2*gnd-length(rs.xy)*5);

float gmask = sat (1-4*gnd);
float stars = 0; int n = 1; float smask = 0;
uv4 = uv2*vec2(0.05,0.5) + vec2(-uTime*0.01,0);
smask = (texture(sampler_pw_noise_lq,uv4))-.7;
stars = clamp01(.1/length(abs(fract(uv4*256)-.5))*smask)/(0.2+4*uv2.x) / (0.5+uv2.x) * sat(length(rs.xy)-0.2);

ret += (1-vUv.y)*vec3(0.0,0.0,0.25)*gmask;
//ret += pow(noise3(vUv*vec2(.1,0.4)+vec2(uTime*0.02,0)).r*(1-vUv.y),2)*gmask*0.07;
ret += gnd/6*vec3(1,1,2); //ret *= (.5+lum(ret));
ret += gmask * sat(stars*stars)*0.7;

// Dioden
uv4 = vUv;
vec3 dio = max(2*max(GetPixel(uv4).r,GetBlur1(uv4).r),GetBlur3(uv4).r*3);
ret += col(dio*q3);

// Spiegelung
vec2 uvm = vUv-(gnd-0.5)*0.02;
vec3 mirr = (GetPixel(uvm).b +GetBlur2(uvm).b*4);
ret += col(mirr*gnd) * !belo;

vec3 beam = 0;
for (int n = 1; n <12; n++) {beam += lum(GetBlur2((uv0-0.5)*(1-1.0*n/12) + 0.5))*(1-1.0*n/12);}
//ret += col(beam.r + beam.b*gnd)*.2*q3;
//ret += clamp01(0.002/pow(length(sin(73*uv2.xy+gnd*0.1))-0.7,2))*gnd;
uv3 =vec2 (1-vUv.x,2-vUv.y);
vec3 shi = sat (4*sin(3*uTime+14*atan(uv3.x,uv3.y))-2)*roam_sin;

//Glas
uv4 = uv0;
ret += pow(GetBlur1(uv4+dz*0.23).g,1)*(1+roam_cos)/2 ;
//ret = GetPixel(vUv);

ret = 1-exp(-ret*2+0.02);

  fragColor = ret;
}
